@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  padding: 0.75rem;
}

.header-card {
  background: white;
  border-radius: 12px;
  padding: 1rem 1.5rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: 72px;
}

.customer-name {
  font-size: 20px;
  font-weight: 700;
  color: #05042E;
  letter-spacing: -0.01em;
}

.header-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 4px;
}

.meta-item {
  font-size: 12px;
  font-weight: 600;
  color: #469BC0;
}

.divider {
  color: #469BC0;
  font-size: 12px;
}

.header-right {
  display: flex;
  align-items: center;
  gap: 8px;
}

.badge {
  font-size: 11px;
  font-weight: 700;
  padding: 4px 12px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.job-type {
  background: rgba(70, 155, 192, 0.2);
  color: #469BC0;
  border: 1px solid #469BC0;
}

.status {
  background: rgba(163, 232, 81, 0.15);
  color: #A3E851;
  border: 1px solid #A3E851;
}

